import re

class NumericEntityUnescaper:
    def __init__(self):
        self._pattern = re.compile(r'&#(x[0-9A-Fa-f]+|\d+);')

    def replace(self, string):
        def _repl(m):
            token = m.group(1)
            try:
                if token.lower().startswith('x'):
                    value = int(token[1:], 16)
                else:
                    value = int(token, 10)
                if 0 <= value <= 0x10FFFF:
                    return chr(value)
            except Exception:
                pass
            return m.group(0)
        return self._pattern.sub(_repl, string)

