    def __init__(self):
        pass

    def replace(self, string):
        out = []
        i = 0
        n = len(string)
        while i < n:
            if string[i] == '&' and i + 1 < n and string[i + 1] == '#':
                j = i + 2
                is_hex = False
                if j < n and (string[j] == 'x' or string[j] == 'X'):
                    is_hex = True
                    j += 1
                start_digits = j
                if is_hex:
                    while j < n and string[j].lower() in '0123456789abcdef':
                        j += 1
                else:
                    while j < n and string[j].isdigit():
                        j += 1
                if j < n and string[j] == ';' and j > start_digits:
                    num_str = string[start_digits:j]
                    try:
                        value = int(num_str, 16 if is_hex else 10)
                        if 0 <= value <= 0x10FFFF:
                            out.append(chr(value))
                            i = j + 1
                            continue
                    except Exception:
                        pass
                out.append(string[i])
                i += 1
            else:
                out.append(string[i])
                i += 1
        return ''.join(out)

