class NumericEntityUnescaper:
    def __init__(self):
        pass

    def replace(self, string):
        parts = string.split('&')
        if not parts:
            return string
        out = [parts[0]]
        for part in parts[1:]:
            if part.startswith('#'):
                semi = part.find(';')
                if semi != -1:
                    token = part[1:semi]
                    if token.startswith(('x', 'X')):
                        num = token[1:]
                        base = 16
                    else:
                        num = token
                        base = 10
                    if num != '':
                        try:
                            val = int(num, base)
                            if 0 <= val <= 0x10FFFF:
                                out.append(chr(val) + part[semi+1:])
                                continue
                        except Exception:
                            pass
                    out.append('&' + part)
                    continue
            out.append('&' + part)
        return ''.join(out)

