import re

class NumericEntityUnescaper:
    def __init__(self):
        self._re = re.compile(r'&#(?:x([0-9A-Fa-f]+)|([0-9]+));')

    def replace(self, string):
        out = []
        last = 0
        for m in self._re.finditer(string):
            out.append(string[last:m.start()])
            hexpart = m.group(1)
            decpart = m.group(2)
            try:
                if hexpart is not None:
                    val = int(hexpart, 16)
                else:
                    val = int(decpart, 10)
                if 0 <= val <= 0x10FFFF:
                    out.append(chr(val))
                else:
                    out.append(m.group(0))
            except Exception:
                out.append(m.group(0))
            last = m.end()
        out.append(string[last:])
        return ''.join(out)

