from copy import deepcopy

class Order:
    def __init__(self):
        self.menu = []  # list of {"dish": str, "price": float, "count": int}
        self.selected_dishes = []  # list of {"dish": str, "price": float, "count": int}
        self.sales = {}  # {"dish": multiplier_float}

    def load_menu(self, menu_items):
        self.menu = [deepcopy(item) for item in menu_items]

    def set_sales(self, sales_map):
        self.sales = dict(sales_map)

    def _find_menu_item(self, name):
        for item in self.menu:
            if item["dish"] == name:
                return item
        return None

    def add_dish(self, dish):
        # Accept a dict with keys "dish", "count", optional "price"
        if not isinstance(dish, dict) or "dish" not in dish or "count" not in dish:
            return False
        name = dish["dish"]
        count = int(dish["count"])
        menu_item = self._find_menu_item(name)
        if menu_item is None:
            return False
        if menu_item["count"] < count:
            return False
        menu_item["count"] -= count
        price = dish.get("price", menu_item["price"])
        # try to merge into selected_dishes
        for sd in self.selected_dishes:
            if sd["dish"] == name and sd["price"] == price:
                sd["count"] += count
                break
        else:
            self.selected_dishes.append({"dish": name, "price": price, "count": count})
        return True

    def calculate_total(self):
        total = 0.0
        for sd in self.selected_dishes:
            mult = self.sales.get(sd["dish"], 1.0)
            total += sd["price"] * sd["count"] * mult
        return total

    def checkout(self):
        if not self.selected_dishes:
            return False
        total = self.calculate_total()
        self.selected_dishes = []
        return total

