from dataclasses import dataclass, field

@dataclass
class MenuItem:
    dish: str
    price: float
    count: int = 0

@dataclass
class SelectedItem:
    dish: str
    price: float
    count: int = 0

class Order:
    def __init__(self):
        self.menu = {}  # dish -> MenuItem
        self.selected = {}  # dish -> SelectedItem
        self.sales = {}  # dish -> multiplier

    def add_menu_item(self, dish: str, price: float, count: int):
        self.menu[dish] = MenuItem(dish, price, count)

    def set_sales(self, sales_map):
        self.sales = dict(sales_map)

    def add_dish(self, dish):
        # dish can be {"dish": name, "count": n, "price": optional}
        if not isinstance(dish, dict) or "dish" not in dish or "count" not in dish:
            return False
        name = dish["dish"]
        count = int(dish["count"])
        if name not in self.menu:
            return False
        menu_item = self.menu[name]
        if menu_item.count < count:
            return False
        menu_item.count -= count
        price = dish.get("price", menu_item.price)
        if name in self.selected:
            sel = self.selected[name]
            if sel.price != price:
                # treat different price as separate selection: create unique key using price
                key = f"{name}__{price}"
                if key not in self.selected:
                    self.selected[key] = SelectedItem(name, price, count)
                else:
                    self.selected[key].count += count
            else:
                sel.count += count
        else:
            self.selected[name] = SelectedItem(name, price, count)
        return True

    def calculate_total(self):
        total = 0.0
        for key, sel in self.selected.items():
            mult = self.sales.get(sel.dish, 1.0)
            total += sel.price * sel.count * mult
        return total

    def checkout(self):
        if not self.selected:
            return False
        total = self.calculate_total()
        self.selected = {}
        return total

