from collections import Counter

class Order:
    def __init__(self):
        # store availability as Counter of dish->count and prices as dict
        self._availability = Counter()
        self._prices = {}
        self.selected = Counter()
        self.sales = {}  # dish -> multiplier

    def set_menu(self, menu_items):
        # menu_items: list of {"dish": name, "price": price, "count": count}
        self._availability = Counter()
        self._prices = {}
        for it in menu_items:
            name = it["dish"]
            self._prices[name] = float(it["price"])
            self._availability[name] += int(it.get("count", 0))

    def set_sales(self, sales_map):
        self.sales = dict(sales_map)

    def add_dish(self, dish):
        # accepts {"dish": name, "count": n} or {"dish": name, "count":n, "price":p}
        if not isinstance(dish, dict):
            return False
        name = dish.get("dish")
        count = int(dish.get("count", 0))
        if not name or count <= 0:
            return False
        if self._availability.get(name, 0) < count:
            return False
        self._availability[name] -= count
        self.selected[name] += count
        return True

    def calculate_total(self):
        total = 0.0
        for name, cnt in self.selected.items():
            price = self._prices.get(name, 0.0)
            mult = self.sales.get(name, 1.0)
            total += price * cnt * mult
        return total

    def checkout(self):
        if not self.selected:
            return False
        t = self.calculate_total()
        self.selected = Counter()
        return t

