import math
from typing import Any, List, Dict, Sequence

class PageUtil:
    def __init__(self, data: Sequence[Any], page_size: int):
        if page_size <= 0:
            raise ValueError("page_size must be positive")
        self.data: List[Any] = list(data)
        self.page_size = int(page_size)
        self.total_items = len(self.data)
        self.total_pages = math.ceil(self.total_items / self.page_size) if self.total_items else 0

    def _valid_page(self, page_number: int) -> bool:
        return 1 <= page_number <= self.total_pages

    def get_page(self, page_number: int) -> List[Any]:
        if not self._valid_page(page_number):
            return []
        start = (page_number - 1) * self.page_size
        end = start + self.page_size
        return self.data[start:end]

    def get_page_info(self, page_number: int) -> Dict[str, Any]:
        if not self._valid_page(page_number):
            return {
                "current_page": page_number,
                "per_page": self.page_size,
                "total_pages": self.total_pages,
                "total_items": self.total_items,
                "has_previous": False,
                "has_next": False,
                "data": []
            }
        start = (page_number - 1) * self.page_size
        end = min(start + self.page_size, self.total_items)
        return {
            "current_page": page_number,
            "per_page": self.page_size,
            "total_pages": self.total_pages,
            "total_items": self.total_items,
            "has_previous": page_number > 1,
            "has_next": page_number < self.total_pages,
            "data": self.data[start:end]
        }

    def search(self, keyword: str) -> Dict[str, Any]:
        keyword_str = str(keyword)
        results = [item for item in self.data if keyword_str in str(item)]
        total_results = len(results)
        total_pages = math.ceil(total_results / self.page_size) if total_results else 0
        return {
            "keyword": keyword,
            "total_results": total_results,
            "total_pages": total_pages,
            "results": results
        }

