from dataclasses import dataclass, field
from typing import Any, List, Dict, Iterator
import math

@dataclass
class PageUtil:
    data: List[Any]
    page_size: int
    total_items: int = field(init=False)
    total_pages: int = field(init=False)

    def __post_init__(self):
        if self.page_size <= 0:
            raise ValueError("page_size must be > 0")
        self.data = list(self.data)
        self.total_items = len(self.data)
        self.total_pages = math.ceil(self.total_items / self.page_size) if self.total_items else 0

    def get_page(self, page_number: int) -> List[Any]:
        if page_number < 1 or page_number > self.total_pages:
            return []
        start = (page_number - 1) * self.page_size
        end = start + self.page_size
        return self.data[start:end]

    def get_page_info(self, page_number: int) -> Dict[str, Any]:
        if page_number < 1 or page_number > self.total_pages:
            return {}
        start = (page_number - 1) * self.page_size
        end = min(start + self.page_size, self.total_items)
        return {
            "current_page": page_number,
            "per_page": self.page_size,
            "total_pages": self.total_pages,
            "total_items": self.total_items,
            "has_previous": page_number > 1,
            "has_next": page_number < self.total_pages,
            "data": self.data[start:end]
        }

    def pages(self) -> Iterator[List[Any]]:
        for p in range(1, self.total_pages + 1):
            yield self.get_page(p)

    def search(self, keyword: str) -> Dict[str, Any]:
        kw = str(keyword)
        matches = [item for item in self.data if kw.lower() in str(item).lower()]
        total = len(matches)
        pages = math.ceil(total / self.page_size) if total else 0
        return {"keyword": keyword, "total_results": total, "total_pages": pages, "results": matches}

