import itertools
from typing import Any, Iterable, List, Dict

class PagerIterator:
    def __init__(self, data: Iterable[Any], page_size: int):
        if page_size <= 0:
            raise ValueError("page_size must be positive")
        self._data_list = list(data)
        self.page_size = page_size
        self.total_items = len(self._data_list)
        self.total_pages = (self.total_items + page_size - 1) // page_size

    def __iter__(self):
        self._current = 1
        return self

    def __next__(self):
        if self._current > self.total_pages:
            raise StopIteration
        page = self.get_page(self._current)
        self._current += 1
        return page

    def get_page(self, page_number: int) -> List[Any]:
        if page_number < 1 or page_number > self.total_pages:
            return []
        start = (page_number - 1) * self.page_size
        return list(itertools.islice(self._data_list, start, start + self.page_size))

    def get_page_info(self, page_number: int) -> Dict[str, Any]:
        if page_number < 1 or page_number > self.total_pages:
            return {}
        start = (page_number - 1) * self.page_size
        end = min(start + self.page_size, self.total_items)
        return {
            "current_page": page_number,
            "per_page": self.page_size,
            "total_pages": self.total_pages,
            "total_items": self.total_items,
            "has_previous": page_number > 1,
            "has_next": page_number < self.total_pages,
            "data": self._data_list[start:end]
        }

    def search(self, keyword: Any) -> Dict[str, Any]:
        k = str(keyword)
        matches = [x for x in self._data_list if k in str(x)]
        total = len(matches)
        pages = (total + self.page_size - 1) // self.page_size
        return {"keyword": keyword, "total_results": total, "total_pages": pages, "results": matches}

