from typing import Any, List, Dict, Callable

def make_pager(data: List[Any], page_size: int):
    if page_size <= 0:
        raise ValueError("page_size must be > 0")
    items = list(data)
    total_items = len(items)
    total_pages = (total_items + page_size - 1) // page_size

    def get_page(page_number: int) -> List[Any]:
        if page_number < 1 or page_number > total_pages:
            return []
        start = (page_number - 1) * page_size
        return items[start:start + page_size]

    def get_page_info(page_number: int) -> Dict[str, Any]:
        if page_number < 1 or page_number > total_pages:
            return {}
        start = (page_number - 1) * page_size
        end = min(start + page_size, total_items)
        return {
            "current_page": page_number,
            "per_page": page_size,
            "total_pages": total_pages,
            "total_items": total_items,
            "has_previous": page_number > 1,
            "has_next": page_number < total_pages,
            "data": items[start:end]
        }

    def search(keyword: Any) -> Dict[str, Any]:
        kw = str(keyword)
        res = [it for it in items if kw in str(it)]
        num = len(res)
        pages = (num + page_size - 1) // page_size
        return {"keyword": keyword, "total_results": num, "total_pages": pages, "results": res}

    return {"get_page": get_page, "get_page_info": get_page_info, "search": search, "total_items": total_items, "total_pages": total_pages}

