class PageHelper:
    def __init__(self, data: List[Any], page_size: int):
        if page_size <= 0:
            raise ValueError("page_size must be positive")
        self._data = list(data)
        self.page_size = int(page_size)
        self.total_items = len(self._data)
        self.total_pages = math.ceil(self.total_items / self.page_size) if self.total_items else 0

    def get_page(self, page_number: int) -> List[Any]:
        if page_number < 1 or page_number > self.total_pages:
            return []
        start = (page_number - 1) * self.page_size
        return self._data[start:start + self.page_size]

    def get_page_info(self, page_number: int) -> Dict[str, Any]:
        if page_number < 1 or page_number > self.total_pages:
            return {}
        start = (page_number - 1) * self.page_size
        end = min(start + self.page_size, self.total_items)
        return {
            "current_page": page_number,
            "per_page": self.page_size,
            "total_pages": self.total_pages,
            "total_items": self.total_items,
            "page_start_index": start,
            "page_end_index": end - 1 if end > start else start,
            "has_previous": page_number > 1,
            "has_next": page_number < self.total_pages,
            "data": self._data[start:end]
        }

    def search(self, keyword: Any) -> Dict[str, Any]:
        k = str(keyword)
        matches = [item for item in self._data if k in str(item)]
        total = len(matches)
        pages = math.ceil(total / self.page_size) if total else 0
        return {"keyword": keyword, "total_results": total, "total_pages": pages, "results": matches}

