import PyPDF2
from pathlib import Path

class PDFUtility:
    def __init__(self, inputs):
        if isinstance(inputs, (str, Path)):
            self.inputs = [str(inputs)]
        else:
            self.inputs = [str(p) for p in inputs]

    def merge_pdfs(self, output_filepath, reverse=False):
        merger = PyPDF2.PdfMerger()
        paths = list(self.inputs)
        if reverse:
            paths = list(reversed(paths))
        for p in paths:
            merger.append(p)
        merger.add_metadata({"Producer": "PDFUtility"})
        merger.write(output_filepath)
        merger.close()
        return output_filepath

    def extract_text_from_pdfs(self):
        pages_text = []
        for p in self.inputs:
            reader = PyPDF2.PdfReader(p)
            for pg in reader.pages:
                pages_text.append(pg.extract_text() or "")
        return pages_text

