class PersonRequest:
    ALLOWED_SEX = {"man": "Man", "woman": "Woman", "ugm": "UGM"}

    def __init__(self, name: Optional[str], sex: Optional[str], phoneNumber: Optional[str]):
        self.name = self._validate_name(name)
        self.sex = self._validate_sex(sex)
        self.phoneNumber = self._validate_phoneNumber(phoneNumber)

    @classmethod
    def from_dict(cls, data: Dict[str, Optional[str]]):
        return cls(data.get("name"), data.get("sex"), data.get("phoneNumber"))

    def _validate_name(self, name: Optional[str]) -> Optional[str]:
        if name is None:
            return None
        name = name.strip()
        if not name or len(name) > 33:
            return None
        return name

    def _validate_sex(self, sex: Optional[str]) -> Optional[str]:
        if sex is None:
            return None
        key = sex.strip().lower()
        return self.ALLOWED_SEX.get(key)

    def _validate_phoneNumber(self, phoneNumber: Optional[str]) -> Optional[str]:
        if phoneNumber is None:
            return None
        phone = phoneNumber.strip()
        if len(phone) == 11 and phone.isdigit():
            return phone
        return None

