class PushBoxGame:
    def __init__(self, map):
        self.map = [list(row) for row in map]
        self.rows = len(self.map)
        self.cols = len(self.map[0]) if self.rows else 0
        self.player_row = 0
        self.player_col = 0
        self.targets = set()
        self.boxes = set()
        self.is_game_over = False
        self.init_game()

    def init_game(self):
        for r in range(self.rows):
            for c in range(self.cols):
                ch = self.map[r][c]
                if ch == "O":
                    self.player_row, self.player_col = r, c
                elif ch == "G":
                    self.targets.add((r, c))
                elif ch == "X":
                    self.boxes.add((r, c))

    def in_bounds(self, r, c):
        return 0 <= r < self.rows and 0 <= c < self.cols

    def is_wall(self, r, c):
        if not self.in_bounds(r, c):
            return True
        return self.map[r][c] == "#"

    def check_win(self):
        return self.targets and self.targets.issubset(self.boxes)

    def move(self, direction):
        moves = {"w": (-1, 0), "s": (1, 0), "a": (0, -1), "d": (0, 1)}
        if direction not in moves:
            return False
        dr, dc = moves[direction]
        nr, nc = self.player_row + dr, self.player_col + dc
        if self.is_wall(nr, nc):
            return False
        if (nr, nc) in self.boxes:
            br, bc = nr + dr, nc + dc
            if self.is_wall(br, bc) or (br, bc) in self.boxes:
                return False
            self.boxes.remove((nr, nc))
            self.boxes.add((br, bc))
            self.player_row, self.player_col = nr, nc
        else:
            self.player_row, self.player_col = nr, nc
        self.is_game_over = self.check_win()
        return self.is_game_over

