class PushBoxGame:
    def __init__(self, grid):
        self.grid = [list(row) for row in grid]
        self.h = len(self.grid)
        self.w = len(self.grid[0]) if self.h else 0
        self.targets = set()
        self.boxes = set()
        self.player = (0, 0)
        self.is_game_over = False
        self._discover()

    def _discover(self):
        for r in range(self.h):
            for c in range(self.w):
                ch = self.grid[r][c]
                if ch == "O":
                    self.player = (r, c)
                elif ch == "G":
                    self.targets.add((r, c))
                elif ch == "X":
                    self.boxes.add((r, c))

    def _restore_cell(self, r, c):
        return "G" if (r, c) in self.targets else " "

    def check_win(self):
        return all(pos in self.boxes for pos in self.targets)

    def move(self, direction):
        dirs = {"w": (-1, 0), "s": (1, 0), "a": (0, -1), "d": (0, 1)}
        if direction not in dirs:
            return False
        dr, dc = dirs[direction]
        pr, pc = self.player
        nr, nc = pr + dr, pc + dc
        if not (0 <= nr < self.h and 0 <= nc < self.w):
            return False
        if self.grid[nr][nc] == "#":
            return False
        if (nr, nc) in self.boxes:
            br, bc = nr + dr, nc + dc
            if not (0 <= br < self.h and 0 <= bc < self.w):
                return False
            if self.grid[br][bc] == "#" or (br, bc) in self.boxes:
                return False
            self.boxes.remove((nr, nc))
            self.boxes.add((br, bc))
            self.grid[br][bc] = "X"
            self.grid[nr][nc] = "O"
            self.grid[pr][pc] = self._restore_cell(pr, pc)
            self.player = (nr, nc)
        else:
            self.grid[nr][nc] = "O"
            self.grid[pr][pc] = self._restore_cell(pr, pc)
            self.player = (nr, nc)
        self.is_game_over = self.check_win()
        return self.is_game_over

