            br, bc = nr + dr, nc + dc
            if self._is_wall(br, bc) or (br, bc) in self.boxes:
                return False
            self.boxes = [(br, bc) if (r, c) == (nr, nc) else (r, c) for (r, c) in self.boxes]
            self.player_row, self.player_col = nr, nc
        else:
            self.player_row, self.player_col = nr, nc
        return self.check_win()

