class ShoppingCart:
    def __init__(self):
        self.items = {}

    def add_item(self, item, price, quantity=1):
        if quantity <= 0:
            return
        if item in self.items:
            existing = self.items[item]
            existing['quantity'] += quantity
            existing['price'] = price
        else:
            self.items[item] = {'price': float(price), 'quantity': int(quantity)}

    def remove_item(self, item, quantity=1):
        if quantity <= 0:
            return
        if item in self.items:
            self.items[item]['quantity'] -= quantity
            if self.items[item]['quantity'] <= 0:
                del self.items[item]

    def view_items(self) -> dict:
        return {k: {'price': v['price'], 'quantity': v['quantity']} for k, v in self.items.items()}

    def total_price(self) -> float:
        return float(sum(v['price'] * v['quantity'] for v in self.items.values()))

