import random
from typing import Tuple

class Snake:
    def __init__(self, SCREEN_WIDTH: int, SCREEN_HEIGHT: int, BLOCK_SIZE: int, food_position: Tuple[int, int]):
        self.SCREEN_WIDTH = SCREEN_WIDTH
        self.SCREEN_HEIGHT = SCREEN_HEIGHT
        self.BLOCK_SIZE = BLOCK_SIZE
        self.length = 1
        # represent positions as grid coordinates (gx, gy) internally
        gx = (SCREEN_WIDTH // 2) // BLOCK_SIZE
        gy = (SCREEN_HEIGHT // 2) // BLOCK_SIZE
        self._grid_size_x = SCREEN_WIDTH // BLOCK_SIZE
        self._grid_size_y = SCREEN_HEIGHT // BLOCK_SIZE
        self._positions_grid = [(gx, gy)]
        self.score = 0
        self.food_position = food_position
        if self._to_pixel(self._positions_grid[0]) == self.food_position:
            self.random_food_position()

    def _to_pixel(self, grid_coord):
        return (grid_coord[0] * self.BLOCK_SIZE, grid_coord[1] * self.BLOCK_SIZE)

    def _from_pixel(self, pixel):
        return (pixel[0] // self.BLOCK_SIZE, pixel[1] // self.BLOCK_SIZE)

    @property
    def positions(self):
        return [self._to_pixel(g) for g in self._positions_grid]

    def move(self, direction: Tuple[int, int]):
        head = self._positions_grid[0]
        dx, dy = direction
        new_grid = ((head[0] + dx) % self._grid_size_x, (head[1] + dy) % self._grid_size_y)
        new_pixel = self._to_pixel(new_grid)
        if new_pixel == self.food_position:
            self.eat_food()
        if new_grid in self._positions_grid[1:]:
            self.reset()
            return
        self._positions_grid.insert(0, new_grid)
        if len(self._positions_grid) > self.length:
            self._positions_grid.pop()

    def random_food_position(self):
        occupied = set(self._positions_grid)
        choices = [(x, y) for x in range(self._grid_size_x) for y in range(self._grid_size_y) if (x, y) not in occupied]
        if not choices:
            return
        gx, gy = random.choice(choices)
        self.food_position = (gx * self.BLOCK_SIZE, gy * self.BLOCK_SIZE)

    def reset(self):
        gx = (self.SCREEN_WIDTH // 2) // self.BLOCK_SIZE
        gy = (self.SCREEN_HEIGHT // 2) // self.BLOCK_SIZE
        self.length = 1
        self._positions_grid = [(gx, gy)]
        self.score = 0
        self.random_food_position()

    def eat_food(self):
        self.length += 1
        self.score += 100
        self.random_food_position()

