import re

class SplitSentence:
    def split_sentences(self, sentences_string):
        text = sentences_string or ""
        sentences = []
        # non-greedy match up to a sentence terminator followed by space or end
        for m in re.finditer(r'.*?[\.!?](?:\s|$)', text, flags=re.S):
            s = m.group().strip()
            if s:
                sentences.append(s)
        # if nothing matched (no terminal punctuation), consider whole text as one sentence
        if not sentences and text.strip():
            sentences = [text.strip()]
        return sentences

    def count_words(self, sentence):
        # remove non-letter characters, then split
        cleaned = re.sub(r'[^A-Za-z\s]', ' ', sentence)
        parts = [p for p in cleaned.split() if p]
        return len(parts)

    def process_text_file(self, sentences_string):
        max_count = 0
        for s in self.split_sentences(sentences_string):
            c = self.count_words(s)
            if c > max_count:
                max_count = c
        return max_count

