class SplitSentence:
    def split_sentences(self, sentences_string):
        text = (sentences_string or "").strip()
        if not text:
            return []
        # scan characters and split on punctuation that likely ends a sentence
        sentences = []
        buf = []
        i = 0
        while i < len(text):
            ch = text[i]
            buf.append(ch)
            if ch in '.!?':
                # lookahead for space or end
                j = i + 1
                # consume following closing quotes or parentheses
                while j < len(text) and text[j] in '\'" )]':
                    buf.append(text[j])
                    j += 1
                if j >= len(text) or text[j].isspace():
                    possible = ''.join(buf).strip()
                    if possible:
                        sentences.append(possible)
                    buf = []
                    i = j
                    continue
            i += 1
        tail = ''.join(buf).strip()
        if tail:
            sentences.append(tail)
        return sentences

    def count_words(self, sentence):
        # split on whitespace and count tokens that contain alphabetic characters
        candidates = sentence.split()
        return sum(1 for w in candidates if re.search(r'[A-Za-z]', w))

    def process_text_file(self, sentences_string):
        max_c = 0
        for sent in self.split_sentences(sentences_string):
            c = self.count_words(sent)
            if c > max_c:
                max_c = c
        return max_c

