class SplitSentence:
    def split_sentences(self, sentences_string):
        text = (sentences_string or "").strip()
        if not text:
            return []
        # get spans of sentences by finding sentence terminators
        spans = []
        start = 0
        for m in re.finditer(r'[\.!?]', text):
            end = m.end()
