            if end == len(text) or text[end].isspace():
                spans.append(text[start:end].strip())
                # skip following whitespace
                k = end
                while k < len(text) and text[k].isspace():
                    k += 1
                start = k
        if start < len(text):
            spans.append(text[start:].strip())
        return [s for s in spans if s]

