    def __init__(self, table_name):
        self.table_name = table_name

    def _escape(self, value):
        if value is None:
            return "NULL"
        if isinstance(value, bool):
            return "1" if value else "0"
        if isinstance(value, (int, float)):
            return str(value)
        s = str(value)
        s = s.replace("'", "''")
        return f"'{s}'"

    def _format_fields(self, fields):
        if fields is None:
            return "*"
        if isinstance(fields, str):
            return fields
        return ", ".join(fields)

    def _format_condition(self, condition):
        if condition is None:
            return None
        if isinstance(condition, dict):
            parts = []
            for k, v in condition.items():
                if v is None:
                    parts.append(f"{k} IS NULL")
                else:
                    parts.append(f"{k} = {self._escape(v)}")
            return " AND ".join(parts)
        return condition

    def select(self, fields=None, condition=None):
        fields_part = self._format_fields(fields)
        cond = self._format_condition(condition)
        sql = f"SELECT {fields_part} FROM {self.table_name}"
        if cond:
            sql += f" WHERE {cond}"
        return sql + ";"

    def insert(self, data):
        keys = ", ".join(data.keys())
        vals = ", ".join(self._escape(v) for v in data.values())
        return f"INSERT INTO {self.table_name} ({keys}) VALUES ({vals});"

    def update(self, data, condition):
