import math
from collections import Counter

class Statistics3:
    @staticmethod
    def mean(data):
        if not data:
            return None
        return sum(data) / len(data)

    @staticmethod
    def median(data):
        if not data:
            return None
        s = sorted(data)
        n = len(s)
        mid = n // 2
        if n % 2 == 1:
            return s[mid]
        return (s[mid - 1] + s[mid]) / 2

    @staticmethod
    def mode(data):
        if not data:
            return None
        counts = Counter(data)
        max_count = max(counts.values())
        modes = [val for val, cnt in counts.items() if cnt == max_count]
        return modes

    @staticmethod
    def standard_deviation(data):
        n = len(data)
        if n < 2:
            return None
        m = Statistics3.mean(data)
        var = sum((x - m) ** 2 for x in data) / (n - 1)
        return math.sqrt(var)

    @staticmethod
    def z_score(data):
        if not data:
            return None
        m = Statistics3.mean(data)
        sd = Statistics3.standard_deviation(data)
        if sd is None or sd == 0:
            return None
        return [(x - m) / sd for x in data]

    @staticmethod
    def correlation(x, y):
        if not x or not y or len(x) != len(y):
            return None
        n = len(x)
        mean_x = Statistics3.mean(x)
        mean_y = Statistics3.mean(y)
        num = sum((xi - mean_x) * (yi - mean_y) for xi, yi in zip(x, y))
        denom_x = sum((xi - mean_x) ** 2 for xi in x)
        denom_y = sum((yi - mean_y) ** 2 for yi in y)
        denom = math.sqrt(denom_x * denom_y)
        if denom == 0:
            return None
        return num / denom

    @staticmethod
    def correlation_matrix(data):
        if not data:
            return []
        # transpose rows->columns
        cols = [list(col) for col in zip(*data)]
        m = len(cols)
        matrix = []
        for i in range(m):
            row = []
            for j in range(m):
                row.append(Statistics3.correlation(cols[i], cols[j]))
            matrix.append(row)
        return matrix

