import math
from collections import defaultdict
import numpy as np

class Statistics3:
    @staticmethod
    def mean(data):
        if not data:
            return None
        return float(np.mean(data))

    @staticmethod
    def median(data):
        if not data:
            return None
        return float(np.median(data))

    @staticmethod
    def mode(data):
        if not data:
            return None
        # handle non-numeric values too
        counts = defaultdict(int)
        for v in data:
            counts[v] += 1
        maxc = max(counts.values())
        return [k for k, c in counts.items() if c == maxc]

    @staticmethod
    def standard_deviation(data):
        n = len(data)
        if n < 2:
            return None
        return float(np.std(data, ddof=1))

    @staticmethod
    def z_score(data):
        if not data:
            return None
        sd = Statistics3.standard_deviation(data)
        if sd is None or sd == 0:
            return None
        m = Statistics3.mean(data)
        return [float((x - m) / sd) for x in data]

    @staticmethod
    def correlation(x, y):
        if not x or not y or len(x) != len(y):
            return None
        x_arr = np.array(x, dtype=float)
        y_arr = np.array(y, dtype=float)
        if x_arr.size < 2:
            return None
        sx = x_arr - x_arr.mean()
        sy = y_arr - y_arr.mean()
        denom = np.sqrt((sx**2).sum() * (sy**2).sum())
        if denom == 0:
            return None
        return float((sx * sy).sum() / denom)

    @staticmethod
    def correlation_matrix(data):
        if not data:
            return []
        arr = np.array(data, dtype=float)
        # arr.shape = (rows, cols) where each row is an observation
        # need correlation of columns
        if arr.ndim == 1:
            return [[None]]
        # np.corrcoef expects variables in rows, so transpose
        try:
            corr = np.corrcoef(arr, rowvar=False)
            # replace NaN with None
            corr_list = corr.tolist()
            for i in range(len(corr_list)):
                for j in range(len(corr_list[i])):
                    if np.isnan(corr_list[i][j]):
                        corr_list[i][j] = None
            return corr_list
        except Exception:
            # fallback to pairwise calculation
            cols = [list(col) for col in zip(*data)]
            m = len(cols)
            result = []
            for i in range(m):
                row = []
                for j in range(m):
                    row.append(Statistics3.correlation(cols[i], cols[j]))
                result.append(row)
            return result

