            for v in data:
                counts[v] = counts.get(v, 0) + 1
            maxc = max(counts.values())
            return [k for k, c in counts.items() if c == maxc]

    @staticmethod
    def standard_deviation(data):
        try:
            # sample standard deviation
            return statistics.stdev(data)
        except statistics.StatisticsError:
            return None

    @staticmethod
    def z_score(data):
        if not data:
            return None
        sd = Statistics3.standard_deviation(data)
        if sd is None or sd == 0:
            return None
        m = Statistics3.mean(data)
        return [(x - m) / sd for x in data]

    @staticmethod
    def correlation(x, y):
        if not x or not y or len(x) != len(y):
            return None
        n = len(x)
        if n < 2:
            return None
        mean_x = Statistics3.mean(x)
        mean_y = Statistics3.mean(y)
        num = sum((xi - mean_x) * (yi - mean_y) for xi, yi in zip(x, y))
        denom = math.sqrt(sum((xi - mean_x) ** 2 for xi in x) * sum((yi - mean_y) ** 2 for yi in y))
        if denom == 0:
            return None
        return num / denom

    @staticmethod
    def correlation_matrix(data):
        if not data:
            return []
        # data is list of observations (rows); compute correlations among columns
        cols = list(zip(*data))
        m = len(cols)
        matrix = []
        for i in range(m):
            row = []
            for j in range(m):
                row.append(Statistics3.correlation(list(cols[i]), list(cols[j])))
            matrix.append(row)
        return matrix

