import math
from collections import defaultdict

class Statistics3:
    @staticmethod
    def mean(data):
        if not data:
            return None
        return sum(data) / len(data)

    @staticmethod
    def median(data):
        if not data:
            return None
        data_sorted = sorted(data)
        n = len(data_sorted)
        if n % 2:
            return data_sorted[n // 2]
        return (data_sorted[n // 2 - 1] + data_sorted[n // 2]) / 2

    @staticmethod
    def mode(data):
        if not data:
            return None
        freq = defaultdict(int)
        for v in data:
            freq[v] += 1
        highest = max(freq.values())
        result = [k for k, v in freq.items() if v == highest]
        # if every value unique, return empty list to indicate no mode
        if highest == 1:
            return []
        return result

    @staticmethod
    def standard_deviation(data):
        n = len(data)
        if n < 2:
            return None
        m = Statistics3.mean(data)
        variance = sum((x - m) ** 2 for x in data) / (n - 1)
        return math.sqrt(variance)

    @staticmethod
    def z_score(data):
        if not data:
            return None
        sd = Statistics3.standard_deviation(data)
        if sd is None or sd == 0:
            return None
        m = Statistics3.mean(data)
        return [(x - m) / sd for x in data]

    @staticmethod
    def correlation(x, y):
        if not x or not y or len(x) != len(y):
            return None
        n = len(x)
        if n < 2:
            return None
        mean_x = Statistics3.mean(x)
        mean_y = Statistics3.mean(y)
        sx = sum((xi - mean_x) ** 2 for xi in x)
        sy = sum((yi - mean_y) ** 2 for yi in y)
        if sx == 0 or sy == 0:
            return None
        cov = sum((xi - mean_x) * (yi - mean_y) for xi, yi in zip(x, y))
        return cov / math.sqrt(sx * sy)

    @staticmethod
    def correlation_matrix(data):
        if not data:
            return []
        # rows are observations, columns are variables
        transposed = list(zip(*data))
        m = len(transposed)
        matrix = [[None] * m for _ in range(m)]
        for i in range(m):
            for j in range(i, m):
                ci = list(transposed[i])
                cj = list(transposed[j])
                corr = Statistics3.correlation(ci, cj)
                matrix[i][j] = corr
                matrix[j][i] = corr
        return matrix

