from collections import Counter

class Statistics3:
    @staticmethod
    def mean(data):
        if not data:
            return None
        return sum(data) / len(data)

    @staticmethod
    def median(data):
        if not data:
            return None
        s = sorted(data)
        n = len(s)
        mid = n // 2
        return s[mid] if n % 2 else (s[mid - 1] + s[mid]) / 2

    @staticmethod
    def mode(data):
        if not data:
            return None
        c = Counter(data)
        most = c.most_common()
        if not most:
            return []
        max_count = most[0][1]
        modes = [val for val, cnt in most if cnt == max_count]
        return modes

    @staticmethod
    def standard_deviation(data):
        n = len(data)
        if n < 2:
            return None
        m = Statistics3.mean(data)
        ss = sum((x - m) ** 2 for x in data)
        return math.sqrt(ss / (n - 1))

    @staticmethod
    def z_score(data):
        if not data:
            return None
        sd = Statistics3.standard_deviation(data)
        if sd is None or sd == 0:
            return None
        m = Statistics3.mean(data)
        return [(x - m) / sd for x in data]

    @staticmethod
    def correlation(x, y):
        if not x or not y or len(x) != len(y):
            return None
        n = len(x)
        if n < 2:
            return None
        mean_x = Statistics3.mean(x)
        mean_y = Statistics3.mean(y)
        sum_xy = sum((xi - mean_x) * (yi - mean_y) for xi, yi in zip(x, y))
        sum_x2 = sum((xi - mean_x) ** 2 for xi in x)
        sum_y2 = sum((yi - mean_y) ** 2 for yi in y)
        denom = math.sqrt(sum_x2 * sum_y2)
        if denom == 0:
            return None
        return sum_xy / denom

    @staticmethod
    def correlation_matrix(data):
        if not data:
            return []
        # data: list of rows (observations)
        cols = [list(col) for col in zip(*data)]
        m = len(cols)
        mat = []
        for i in range(m):
            row = []
            for j in range(m):
                row.append(Statistics3.correlation(cols[i], cols[j]))
            mat.append(row)
        return mat

