from dataclasses import dataclass


@dataclass
class Student:
    name: str
    age: int
    gender: str
    grade: int


class StudentDatabaseProcessor:
    def __init__(self, database_name):
        self.database_name = database_name
        self.conn = sqlite3.connect(self.database_name)
        self.conn.row_factory = sqlite3.Row
        self.create_student_table()

    def __enter__(self):
        return self

    def __exit__(self, exc_type, exc, tb):
        self.conn.close()

    def close(self):
        self.conn.close()

    def create_student_table(self):
        cursor = self.conn.cursor()
        cursor.execute(
            "CREATE TABLE IF NOT EXISTS students (id INTEGER PRIMARY KEY, name TEXT, age INTEGER, gender TEXT, grade INTEGER)"
        )
        self.conn.commit()

    def insert_student(self, student: Student):
        cursor = self.conn.cursor()
        cursor.execute(
            "INSERT INTO students (name, age, gender, grade) VALUES (?, ?, ?, ?)",
            (student.name, student.age, student.gender, student.grade),
        )
        self.conn.commit()

    def search_student_by_name(self, name):
        cursor = self.conn.cursor()
        cursor.execute("SELECT * FROM students WHERE name = ?", (name,))
        rows = cursor.fetchall()
        return [Student(row["name"], row["age"], row["gender"], row["grade"]) for row in rows]

    def delete_student_by_name(self, name):
        cursor = self.conn.cursor()
        cursor.execute("DELETE FROM students WHERE name = ?", (name,))
        self.conn.commit()

