import shutil
from typing import Any

class TextFileProcessor:
    def __init__(self, file_path: str):
        self.file_path = file_path

    def read_file_as_json(self) -> Any:
        with open(self.file_path, 'r', encoding='utf-8') as f:
            return json.load(f)

    def read_file(self) -> str:
        with open(self.file_path, 'r', encoding='utf-8') as f:
            return f.read()

    def write_file(self, content: str) -> None:
        with open(self.file_path, 'w', encoding='utf-8') as f:
            f.write(content)

    def process_file(self) -> str:
        temp = tempfile.NamedTemporaryFile(mode='w', delete=False, encoding='utf-8')
        out_name = temp.name
        written_chars = []
        with open(self.file_path, 'r', encoding='utf-8') as src, temp:
            for line in src:
                filtered_line = ''.join(ch for ch in line if ch.isalpha())
                if filtered_line:
                    temp.write(filtered_line)
                    written_chars.append(filtered_line)
        shutil.move(out_name, self.file_path)
        result = ''.join(written_chars)
        return result

