import math

@dataclass
class Thermostat:
    current_temperature: float
    target_temperature: float
    mode: str

    def get_target_temperature(self):
        return self.target_temperature

    def set_target_temperature(self, temperature):
        self.target_temperature = float(temperature)
        return True

    def get_mode(self):
        return self.mode

    def set_mode(self, mode):
        if mode in ('heat', 'cool'):
            self.mode = mode
            return True
        return False

    def auto_set_mode(self):
        if self.current_temperature < self.target_temperature:
            self.mode = 'heat'
        else:
            self.mode = 'cool'

    def auto_check_conflict(self):
        if self.current_temperature > self.target_temperature:
            if self.mode == 'cool':
                return True
            else:
                self.auto_set_mode()
                return False
        else:
            if self.mode == 'heat':
                return True
            else:
                self.auto_set_mode()
                return False

    def simulate_operation(self):
        self.auto_set_mode()
        diff = abs(self.target_temperature - self.current_temperature)
        steps = math.ceil(diff)
        if steps == 0:
            return 0
        step_dir = 1 if self.target_temperature > self.current_temperature else -1
        for _ in range(steps):
            self.current_temperature += step_dir
        return steps

