        self.auto_set_mode()
        diff = abs(self.target_temperature - self.current_temperature)
        def recurse(curr, tgt, remaining):
            if remaining == 0:
                return 0
            if curr < tgt:
                return 1 + recurse(curr + 1, tgt, remaining - 1)
            else:
                return 1 + recurse(curr - 1, tgt, remaining - 1)
        steps = recurse(self.current_temperature, self.target_temperature, diff)
        self.current_temperature = self.target_temperature
        return steps

