            if first != ' ' and all(self.board[r][c] == first for c in range(1, N)):
                return first
        for c in range(N):
            first = self.board[0][c]
            if first != ' ' and all(self.board[r][c] == first for r in range(1, N)):
                return first
        first = self.board[0][0]
        if first != ' ' and all(self.board[i][i] == first for i in range(1, N)):
            return first
        first = self.board[0][N-1]
        if first != ' ' and all(self.board[i][N-1-i] == first for i in range(1, N)):
            return first
        return None

    def is_board_full(self):
        return all(cell != ' ' for row in self.board for cell in row)

