            for r in self.board:
                if set(r) == target:
                    return player
            for c in zip(*self.board):
                if set(c) == target:
                    return player
            if all(self.board[i][i] == player for i in range(self.N)):
                return player
            if all(self.board[i][self.N-1-i] == player for i in range(self.N)):
                return player
        return None

    def is_board_full(self):
        return not any(' ' in row for row in self.board)

