class TicTacToe:
    def __init__(self, N=3):
        self.N = N
        self._flat = [' '] * (N * N)
        self.current_player = 'X'

    def _idx(self, row, col):
        return row * self.N + col

    def make_move(self, row, col):
        if not (0 <= row < self.N and 0 <= col < self.N):
            raise IndexError("Move out of bounds")
        i = self._idx(row, col)
        if self._flat[i] != ' ':
            raise ValueError("Cell already occupied")
        self._flat[i] = self.current_player
        self.current_player = 'O' if self.current_player == 'X' else 'X'
        return True

    def check_winner(self):
        N = self.N
        lines = []
        for r in range(N):
            lines.append([self._flat[self._idx(r, c)] for c in range(N)])
        for c in range(N):
            lines.append([self._flat[self._idx(r, c)] for r in range(N)])
        lines.append([self._flat[self._idx(i, i)] for i in range(N)])
        lines.append([self._flat[self._idx(i, N-1-i)] for i in range(N)])
        for line in lines:
            if line[0] != ' ' and all(x == line[0] for x in line):
                return line[0]
        return None

    def is_board_full(self):
        return ' ' not in self._flat

