    @staticmethod
    def get_current_date() -> str:
        return datetime.datetime.now().strftime("%Y-%m-%d")

    @staticmethod
    def add_seconds(seconds: Union[int, float]) -> str:
        new_dt = datetime.datetime.now() + datetime.timedelta(seconds=seconds)
