        try:
            return datetime.datetime.strptime(string, "%Y-%m-%d %H:%M:%S").replace(tzinfo=self.tz)
        except ValueError:
            return datetime.datetime.fromisoformat(string)

    def datetime_to_string(self, dt: datetime.datetime) -> str:
        if dt.tzinfo is None and self.tz is not None:
            dt = dt.replace(tzinfo=self.tz)
        return dt.strftime("%Y-%m-%d %H:%M:%S")

    def get_minutes(self, string_time1: str, string_time2: str) -> int:
        t1 = self.string_to_datetime(string_time1)
        t2 = self.string_to_datetime(string_time2)
        secs = (t2 - t1).total_seconds()
        return int(math.ceil(secs / 60.0))

    def get_format_time(self, year: int, month: int, day: int, hour: int, minute: int, second: int) -> str:
        dt = datetime.datetime(year, month, day, hour, minute, second, tzinfo=self.tz)
        return dt.strftime("%Y-%m-%d %H:%M:%S")

