import random
from collections import Counter

class TwentyFourPointGame:
    def __init__(self) -> None:
        self.nums = []

    def _generate_cards(self):
        for i in range(4):
            self.nums.append(random.randint(1, 9))
        assert len(self.nums) == 4

    def get_my_cards(self):
        self.nums = []
        self._generate_cards()
        return self.nums

    def _tokenize(self, expr):
        tokens = []
        i = 0
        n = len(expr)
        while i < n:
            c = expr[i]
            if c.isspace():
                i += 1
                continue
            if c.isdigit():
                j = i
                while j < n and expr[j].isdigit():
                    j += 1
                tokens.append(expr[i:j])
                i = j
                continue
            if c in '+-*/()':
                tokens.append(c)
                i += 1
                continue
            return None
        return tokens

    def _to_postfix(self, tokens):
        prec = {'+':1,'-':1,'*':2,'/':2}
        out = []
        stack = []
        for t in tokens:
            if t.isdigit():
                out.append(t)
            elif t in '+-*/':
                while stack and stack[-1] != '(' and prec[stack[-1]] >= prec[t]:
                    out.append(stack.pop())
                stack.append(t)
            elif t == '(':
                stack.append(t)
            elif t == ')':
                while stack and stack[-1] != '(':
                    out.append(stack.pop())
                if not stack or stack[-1] != '(':
                    return None
                stack.pop()
            else:
                return None
        while stack:
            if stack[-1] in '()':
                return None
            out.append(stack.pop())
        return out

    def _eval_postfix(self, pf):
        stack = []
        for t in pf:
            if t.isdigit():
                stack.append(float(t))
            else:
                if len(stack) < 2:
                    return None
                b = stack.pop()
                a = stack.pop()
                if t == '+':
                    stack.append(a+b)
                elif t == '-':
                    stack.append(a-b)
                elif t == '*':
                    stack.append(a*b)
                elif t == '/':
                    if b == 0:
                        return None
                    stack.append(a/b)
        if len(stack) != 1:
            return None
        return stack[0]

    def answer(self, expression):
        if expression == 'pass':
            return self.get_my_cards()
        tokens = self._tokenize(expression)
        if tokens is None:
            return False
        numbers = [int(t) for t in tokens if t.isdigit()]
        if Counter(numbers) != Counter(self.nums):
            return False
        pf = self._to_postfix(tokens)
        if pf is None:
            return False
        val = self._eval_postfix(pf)
        if val is None:
            return False
        return abs(val - 24.0) < 1e-9

