class URLHandler:
    def __init__(self, url):
        self.url = url
        self._parsed = urlparse(url)

    def get_scheme(self):
        return self._parsed.scheme or None

    def get_host(self):
        return self._parsed.netloc or None

    def get_path(self):
        return self._parsed.path or None

    def get_query_params(self):
        if not self._parsed.query:
            return None
        raw = parse_qs(self._parsed.query, keep_blank_values=True)
        return {k: v[0] if v else '' for k, v in raw.items()}

    def get_fragment(self):
        return self._parsed.fragment or None

