class URLHandler:
    def __init__(self, url):
        self.url = url

    def get_scheme(self):
        idx = self.url.find("://")
        if idx == -1:
            return None
        return self.url[:idx]

    def get_host(self):
        idx = self.url.find("://")
        if idx == -1:
            return None
        start = idx + 3
        end = self.url.find("/", start)
        if end == -1:
            host = self.url[start:]
        else:
            host = self.url[start:end]
        return host if host != "" else None

    def get_path(self):
        idx = self.url.find("://")
        if idx == -1:
            return None
        start = idx + 3
        slash = self.url.find("/", start)
        if slash == -1:
            return None
        # path ends before ? or #
        q = self.url.find("?", slash)
        h = self.url.find("#", slash)
        end = len(self.url)
        if q != -1:
            end = min(end, q)
        if h != -1:
            end = min(end, h)
        return self.url[slash:end] if end > slash else None

    def get_query_params(self):
        q = self.url.find("?")
        if q == -1:
            return None
        h = self.url.find("#", q)
        if h == -1:
            query = self.url[q+1:]
        else:
            query = self.url[q+1:h]
        params = {}
        if query == "":
            return {}
        for part in query.split("&"):
            if part == "":
                continue
            k, sep, v = part.partition("=")
            if sep == "":
                continue
            params[k] = v
        return params

    def get_fragment(self):
        h = self.url.find("#")
        if h == -1:
            return None
        return self.url[h+1:]

