import re

class URLHandler:
    _RE = re.compile(
        r'^(?:(?P<scheme>[^:/?#]+):)?'          # scheme
        r'(?://(?P<host>[^/?#]*))?'            # host
        r'(?P<path>[^?#]*)'                    # path
        r'(?:\?(?P<query>[^#]*))?'             # query
        r'(?:#(?P<fragment>.*))?'              # fragment
    )

    def __init__(self, url):
        self.url = url
        self._m = self._RE.match(url)

    def get_scheme(self):
        if not self._m:
            return None
        s = self._m.group('scheme')
        return s if s else None

    def get_host(self):
        if not self._m:
            return None
        h = self._m.group('host')
        return h if h else None

    def get_path(self):
        if not self._m:
            return None
        p = self._m.group('path')
        return p if p != "" else None

    def get_query_params(self):
        if not self._m:
            return None
        q = self._m.group('query')
        if q is None:
            return None
        if q == "":
