class URLHandler:
    def __init__(self, url):
        self.url = url

    def _split_first(self, s, sep):
        if sep in s:
            i = s.index(sep)
            return s[:i], s[i+len(sep):]
        return None, s

    def get_scheme(self):
        head, rest = self._split_first(self.url, "://")
        return head if head is not None else None

    def get_host(self):
        head, rest = self._split_first(self.url, "://")
        if head is None:
            return None
        before_frag, frag = self._split_first(rest, "#")
        before_query, query = self._split_first(before_frag, "?")
        host, path_rest = self._split_first(before_query, "/")
        if host is None:
            host = before_query
        return host if host != "" else None

    def get_path(self):
        head, rest = self._split_first(self.url, "://")
        if head is None:
            return None
        before_frag, frag = self._split_first(rest, "#")
        before_query, query = self._split_first(before_frag, "?")
        host, path_rest = self._split_first(before_query, "/")
        if path_rest == "" or path_rest is None:
            return None
        return "/" + path_rest

    def get_query_params(self):
        q_index = self.url.find("?")
        if q_index == -1:
            return None
        after_q = self.url[q_index+1:]
        frag_index = after_q.find("#")
        if frag_index != -1:
            query = after_q[:frag_index]
        else:
            query = after_q
        if query == "":
            return {}
        params = {}
        for part in query.split("&"):
            if not part:
                continue
            k, sep, v = part.partition("=")
            if sep == "":
                continue
            params[k] = v
        return params

    def get_fragment(self):
        i = self.url.find("#")
        if i == -1:
            return None
        return self.url[i+1:]

