import urllib.parse


class UrlPath:
    def __init__(self):
        self.segments = []
        self.with_end_tag = False

    def add(self, segment):
        self.segments.append(self.fix_path(segment))

    def parse(self, path, charset):
        if path:
            if path.endswith('/'):
                self.with_end_tag = True
            path = self.fix_path(path)
            if path:
                i = 0
                start = 0
                s = path
                n = len(s)
                while i <= n:
                    if i == n or s[i] == '/':
                        seg = s[start:i]
                        decoded = urllib.parse.unquote(seg, encoding=charset)
                        self.segments.append(decoded)
                        start = i + 1
                    i += 1

    @staticmethod
    def fix_path(path):
        if not path:
            return ''
        # manual strip to avoid creating intermediate strings beyond necessary
        start = 0
        end = len(path) - 1
        while start <= end and path[start] == '/':
            start += 1
        while end >= start and path[end] == '/':
            end -= 1
        if start > end:
            return ''
        return path[start:end+1]

