import urllib.parse
from typing import List


class UrlPath:
    def __init__(self):
        self.segments: List[str] = []
        self.with_end_tag: bool = False

    def add(self, segment: str) -> None:
        self.segments.append(self.fix_path(segment))

    def parse(self, path: str, charset: str) -> None:
        if path:
            self.with_end_tag = path.endswith('/')
            path = self.fix_path(path)
            if path:
                for part in path.split('/'):
                    self.segments.append(urllib.parse.unquote(part, encoding=charset))

    @staticmethod
    def fix_path(path: str) -> str:
        if not path:
            return ''
        return path.strip('/')

