import sqlite3
import hashlib
import secrets

class UserLoginDB:
    def __init__(self, db_name):
        self.conn = sqlite3.connect(db_name)
        self.cur = self.conn.cursor()
        self.cur.execute('''
            CREATE TABLE IF NOT EXISTS users (
                id INTEGER PRIMARY KEY,
                username TEXT UNIQUE,
                salt TEXT,
                pw_hash TEXT
            )
        ''')
        self.conn.commit()

    def _derive(self, password, salt):
        return hashlib.pbkdf2_hmac('sha256', password.encode('utf-8'), salt, 200000).hex()

    def insert_user(self, username, password):
        salt = secrets.token_bytes(16)
        pw_hash = self._derive(password, salt)
        self.cur.execute('INSERT INTO users (username, salt, pw_hash) VALUES (?, ?, ?)', (username, salt.hex(), pw_hash))
        self.conn.commit()

    def search_user_by_username(self, username):
        self.cur.execute('SELECT id, username, salt, pw_hash FROM users WHERE username = ?', (username,))
        row = self.cur.fetchone()
        if row is None:
            return None
        return {'id': row[0], 'username': row[1], 'salt': bytes.fromhex(row[2]), 'pw_hash': row[3]}

    def delete_user_by_username(self, username):
        self.cur.execute('DELETE FROM users WHERE username = ?', (username,))
        self.conn.commit()

    def validate_user_login(self, username, password):
        user = self.search_user_by_username(username)
        if not user:
            return False
        return self._derive(password, user['salt']) == user['pw_hash']

