import numpy as np


class VectorUtil:
    @staticmethod
    def _unitvec(v):
        v = np.asarray(v, dtype=float)
        norm = np.linalg.norm(v)
        if norm == 0 or not np.isfinite(norm):
            return np.zeros_like(v)
        return v / norm

    @staticmethod
    def similarity(vector_1, vector_2):
        u1 = VectorUtil._unitvec(vector_1)
        u2 = VectorUtil._unitvec(vector_2)
        return float(np.dot(u1, u2))

    @staticmethod
    def cosine_similarities(vector_1, vectors_all):
        v1 = np.asarray(vector_1, dtype=float)
        mat = np.asarray(vectors_all, dtype=float)
        if mat.ndim == 1:
            mat = mat.reshape(1, -1)
        norms1 = np.linalg.norm(v1)
        norms_all = np.linalg.norm(mat, axis=1)
        dot_products = mat.dot(v1)
        denom = norms1 * norms_all
        with np.errstate(divide='ignore', invalid='ignore'):
            sims = np.divide(dot_products, denom)
            sims = np.nan_to_num(sims, nan=0.0, posinf=0.0, neginf=0.0)
        return sims

    @staticmethod
    def n_similarity(vector_list_1, vector_list_2):
        a = np.asarray(vector_list_1, dtype=float)
        b = np.asarray(vector_list_2, dtype=float)
        if a.size == 0 or b.size == 0:
            raise ZeroDivisionError('At least one of the passed list is empty.')
        mean_a = a.mean(axis=0)
        mean_b = b.mean(axis=0)
        return VectorUtil.similarity(mean_a, mean_b)

    @staticmethod
    def compute_idf_weight_dict(total_num, number_dict):
        total_num = float(total_num)
        if total_num <= 0:
            raise ValueError("total_num must be positive")
        result = {}
        for key, count in number_dict.items():
            c = float(count)
            w = np.log((total_num + 1.0) / (c + 1.0))
            result[key] = float(w)
        return result

