import numpy as np


class VectorUtil:
    @staticmethod
    def similarity(vector_1, vector_2):
        v1 = np.asarray(vector_1, dtype=float)
        v2 = np.asarray(vector_2, dtype=float)
        norm1 = np.linalg.norm(v1)
        norm2 = np.linalg.norm(v2)
        if norm1 == 0 or norm2 == 0:
            return 0.0
        return float(np.dot(v1, v2) / (norm1 * norm2))

    @staticmethod
    def cosine_similarities(vector_1, vectors_all):
        v1 = np.asarray(vector_1, dtype=float)
        mat = np.asarray(vectors_all, dtype=float)
        if mat.ndim == 1:
            mat = mat.reshape(1, -1)
        dot_products = np.einsum('ij,j->i', mat, v1)
        norms_mat = np.linalg.norm(mat, axis=1)
        norm_v1 = np.linalg.norm(v1)
        denom = norms_mat * norm_v1
        with np.errstate(divide='ignore', invalid='ignore'):
            sims = np.divide(dot_products, denom)
            sims[~np.isfinite(sims)] = 0.0
        return sims

    @staticmethod
    def n_similarity(vector_list_1, vector_list_2):
        A = np.asarray(vector_list_1, dtype=float)
        B = np.asarray(vector_list_2, dtype=float)
        if A.size == 0 or B.size == 0:
            raise ZeroDivisionError('At least one of the passed list is empty.')
        meanA = A.mean(axis=0)
        meanB = B.mean(axis=0)
        return VectorUtil.similarity(meanA, meanB)

    @staticmethod
    def compute_idf_weight_dict(total_num, number_dict):
        if total_num <= 0:
            raise ValueError("total_num must be > 0")
        keys = list(number_dict.keys())
        counts = np.array([float(number_dict[k]) for k in keys], dtype=float)
        weights = np.log((total_num + 1.0) / (counts + 1.0))
        return {k: float(w) for k, w in zip(keys, weights)}

