import numpy as np


class VectorUtil:
    @staticmethod
    def similarity(vector_1, vector_2):
        a = np.asarray(vector_1, dtype=float)
        b = np.asarray(vector_2, dtype=float)
        if a.shape != b.shape:
            a = a.ravel()
            b = b.ravel()
        na = np.linalg.norm(a)
        nb = np.linalg.norm(b)
        if na == 0 or nb == 0:
            return 0.0
        return (a @ b) / (na * nb)

    @staticmethod
    def cosine_similarities(vector_1, vectors_all):
        v = np.asarray(vector_1, dtype=float)
        M = np.asarray(vectors_all, dtype=float)
        if M.ndim == 1:
            M = M.reshape(1, -1)
        norms = np.linalg.norm(M, axis=1)
        nv = np.linalg.norm(v)
        denom = norms * nv
        dotp = M @ v
        sims = np.zeros_like(dotp, dtype=float)
        mask = denom != 0
        sims[mask] = dotp[mask] / denom[mask]
        return sims

    @staticmethod
    def n_similarity(vector_list_1, vector_list_2):
        X = np.asarray(vector_list_1, dtype=float)
        Y = np.asarray(vector_list_2, dtype=float)
        if X.size == 0 or Y.size == 0:
            raise ZeroDivisionError('At least one of the passed list is empty.')
        mx = X.mean(axis=0)
        my = Y.mean(axis=0)
        return VectorUtil.similarity(mx, my)

    @staticmethod
    def compute_idf_weight_dict(total_num, number_dict):
        total_num = float(total_num)
        if total_num <= 0:
            raise ValueError("total_num must be > 0")
        return {k: float(np.log((total_num + 1.0) / (float(v) + 1.0))) for k, v in number_dict.items()}

