        v2 = np.asarray(vector_2, dtype=float).ravel()
        denom = np.linalg.norm(v1) * np.linalg.norm(v2)
        if denom == 0:
            return 0.0
        return float(np.dot(v1, v2) / denom)

    @staticmethod
    def cosine_similarities(vector_1, vectors_all):
        v = np.asarray(vector_1, dtype=float).ravel()
        mat = np.asarray(vectors_all, dtype=float)
        if mat.ndim == 1:
            mat = mat.reshape(1, -1)
        dp = np.dot(mat, v)
        norms = np.linalg.norm(mat, axis=1) * np.linalg.norm(v)
        sims = np.where(norms != 0, dp / norms, 0.0)
        return sims

    @staticmethod
    def n_similarity(vector_list_1, vector_list_2):
        A = np.asarray(vector_list_1, dtype=float)
        B = np.asarray(vector_list_2, dtype=float)
        if A.size == 0 or B.size == 0:
            raise ZeroDivisionError('At least one of the passed list is empty.')
        meanA = A.mean(axis=0)
        meanB = B.mean(axis=0)
        return VectorUtil.similarity(meanA, meanB)

    @staticmethod
    def compute_idf_weight_dict(total_num, number_dict):
        total_num = float(total_num)
        if total_num <= 0:
            raise ValueError("total_num must be positive")
        keys = list(number_dict.keys())
        counts = [float(number_dict[k]) for k in keys]
        weights = [float(np.log((total_num + 1.0) / (c + 1.0))) for c in counts]
        return dict(zip(keys, weights))

