from dataclasses import dataclass

@dataclass
class Product:
    product_id: str
    name: str
    quantity: int

@dataclass
class Order:
    order_id: str
    product_id: str
    quantity: int
    status: str

class Warehouse:
    def __init__(self):
        self.inventory = {}
        self.orders = {}

    def add_product(self, product_id, name, quantity):
        if product_id in self.inventory:
            self.inventory[product_id].quantity += quantity
        else:
            self.inventory[product_id] = Product(product_id, name, quantity)
        return True

    def update_product_quantity(self, product_id, quantity):
        prod = self.inventory.get(product_id)
        if not prod:
            return False
        new_qty = prod.quantity + quantity
        if new_qty < 0:
            return False
        prod.quantity = new_qty
        return True

    def get_product_quantity(self, product_id):
        prod = self.inventory.get(product_id)
        if prod is None:
            return None
        return prod.quantity

    def create_order(self, order_id, product_id, quantity):
        prod = self.inventory.get(product_id)
        if prod is None or prod.quantity < quantity:
            return False
        prod.quantity -= quantity
        self.orders[order_id] = Order(order_id, product_id, quantity, 'Shipped')
        return True

    def change_order_status(self, order_id, status):
        order = self.orders.get(order_id)
        if order is None:
            return False
        order.status = status
        return True

    def track_order(self, order_id):
        order = self.orders.get(order_id)
        if order is None:
            return None
        return order.status

