from typing import Dict

class Warehouse:
    def __init__(self):
        self.inventory: Dict[str, Dict[str, int]] = {}
        self.orders: Dict[str, Dict[str, object]] = {}

    def add_product(self, product_id: str, name: str, quantity: int):
        if quantity < 0:
            raise ValueError("Quantity must be non-negative")
        if product_id in self.inventory:
            self.inventory[product_id]['quantity'] += quantity
        else:
            self.inventory[product_id] = {'name': name, 'quantity': quantity}
        return None

    def update_product_quantity(self, product_id: str, quantity: int):
        if product_id not in self.inventory:
            raise KeyError("Product not found")
        if self.inventory[product_id]['quantity'] + quantity < 0:
            raise ValueError("Insufficient stock to decrement")
        self.inventory[product_id]['quantity'] += quantity
        return None

    def get_product_quantity(self, product_id: str) -> int:
        if product_id not in self.inventory:
            raise KeyError("Product not found")
        return self.inventory[product_id]['quantity']

    def create_order(self, order_id: str, product_id: str, quantity: int):
        if product_id not in self.inventory:
            raise KeyError("Product not found")
        if quantity <= 0:
            raise ValueError("Quantity must be positive")
        available = self.inventory[product_id]['quantity']
        if available < quantity:
            raise ValueError("Insufficient stock")
        self.inventory[product_id]['quantity'] = available - quantity
        self.orders[order_id] = {'product_id': product_id, 'quantity': quantity, 'status': 'Shipped'}
        return self.orders[order_id]

    def change_order_status(self, order_id: str, status: str):
        if order_id not in self.orders:
            raise KeyError("Order not found")
        self.orders[order_id]['status'] = status
        return None

    def track_order(self, order_id: str) -> str:
        if order_id not in self.orders:
            raise KeyError("Order not found")
        return self.orders[order_id]['status']

