import threading
from collections import defaultdict

class Warehouse:
    def __init__(self):
        self._lock = threading.Lock()
        self.inventory = defaultdict(lambda: {'name': '', 'quantity': 0})
        self.orders = {}

    def add_product(self, product_id, name, quantity):
        if quantity <= 0:
            return False
        with self._lock:
            if self.inventory[product_id]['name'] == '':
                self.inventory[product_id]['name'] = name
            self.inventory[product_id]['quantity'] += quantity
        return True

    def update_product_quantity(self, product_id, quantity):
        with self._lock:
            if product_id not in self.inventory or self.inventory[product_id]['name'] == '':
                return False
            if self.inventory[product_id]['quantity'] + quantity < 0:
                return False
            self.inventory[product_id]['quantity'] += quantity
        return True

    def get_product_quantity(self, product_id):
        with self._lock:
            info = self.inventory.get(product_id)
            if not info or info['name'] == '':
                return 0
            return info['quantity']

    def create_order(self, order_id, product_id, quantity):
        if quantity <= 0:
            return False
        with self._lock:
            info = self.inventory.get(product_id)
            if not info or info['name'] == '':
                return False
            if info['quantity'] < quantity:
                return False
            info['quantity'] -= quantity
            self.orders[order_id] = {'product_id': product_id, 'quantity': quantity, 'status': 'Shipped'}
        return True

    def change_order_status(self, order_id, status):
        with self._lock:
            if order_id not in self.orders:
                return False
            self.orders[order_id]['status'] = status
        return True

    def track_order(self, order_id):
        with self._lock:
            order = self.orders.get(order_id)
            if not order:
                return False
            return order['status']

