import itertools

class Warehouse:
    def __init__(self):
        self.inventory = {}
        self.orders = {}
        self._oid_gen = itertools.count(1)

    def add_product(self, product_id, name, quantity):
        if product_id in self.inventory:
            self.inventory[product_id]['quantity'] += quantity
        else:
            self.inventory[product_id] = {'name': name, 'quantity': quantity}
        return self.inventory[product_id]['quantity']

    def update_product_quantity(self, product_id, quantity):
        if product_id not in self.inventory:
            return False
        new_q = self.inventory[product_id]['quantity'] + quantity
        if new_q < 0:
            return False
        self.inventory[product_id]['quantity'] = new_q
        return True

    def get_product_quantity(self, product_id):
        return self.inventory.get(product_id, {}).get('quantity', 0)

    def create_order(self, order_id=None, product_id=None, quantity=0):
        if product_id is None or quantity <= 0:
            return False
        if order_id is None:
            order_id = f"ORD{next(self._oid_gen)}"
        qty = self.get_product_quantity(product_id)
        if qty < quantity:
            return False
        self.update_product_quantity(product_id, -quantity)
        self.orders[order_id] = {'product_id': product_id, 'quantity': quantity, 'status': 'Shipped'}
        return order_id

    def change_order_status(self, order_id, status):
        if order_id not in self.orders:
            return False
        self.orders[order_id]['status'] = status
        return True

    def track_order(self, order_id):
        return self.orders.get(order_id, {}).get('status', False)
